mapper.update:
UPDATE esg.tb_manage_doc
SET
    write_dt = #{writeDt},
    writer_id = #{writerId},
    manage_doc_nm = #{manageDocNm},
    use_yn = #{useYn},
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE comp_id = #{compId}
  AND write_year = #{writeYear}
  AND doc_no = #{docNo}
  AND doc_type = #{docType}

mapper.delete:
UPDATE esg.tb_manage_doc
SET
    use_yn = 'N',
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE comp_id = #{compId}
  AND write_year = #{writeYear}
  AND doc_no = #{docNo}
  AND doc_type = #{docType}

mapper.select:
SELECT *
FROM esg.tb_manage_doc
WHERE comp_id = #{compId}
  AND write_year = #{writeYear}
  AND doc_no = #{docNo}
  AND doc_type = #{docType}
